import React from "react";

function Dashboard() {
  return (
    <div>
      <h2>Dashboard</h2>
      <div className="cards">
        <div className="card">Products</div>
        <div className="card">Dealers</div>
        <div className="card">Inventory</div>
        <div className="card">Orders</div>
      </div>
    </div>
  );
}

export default Dashboard;
